def sum_even(arr):
    total = 0
    for x in arr:
        if x % 2 == 0:
            total += x
    return total

def build_user_total(records):
    totals = {}
    for row in records:
        user = row['user']
        totals[user] = totals.get(user, 0) + row['amount']
    return totals
